const schemaRows = $('Scan DB Structure').all();
const directivesItem = $('Set Directives').first();
const directives = directivesItem ? directivesItem.json.directives : 'No directives provided.';

if (schemaRows.length === 0) {
  return [{ json: { text: 'No database tables found.', directives } }];
}

const schemas = {};
schemaRows.forEach(row => {
  const d = row.json;
  if (!schemas[d.schema_name]) {
    schemas[d.schema_name] = {};
  }
  if (!schemas[d.schema_name][d.table_name]) {
    schemas[d.schema_name][d.table_name] = [];
  }
  schemas[d.schema_name][d.table_name].push({
    column: d.column_name,
    type: d.data_type,
    description: d.column_description || ''
  });
});

let text = 'PostgreSQL Database Schema and Column Documentation:\n\n';
for (const [schemaName, tables] of Object.entries(schemas)) {
  text += `Schema: ${schemaName}\n`;
  for (const [tableName, columns] of Object.entries(tables)) {
    text += `  Table: ${tableName}\n`;
    columns.forEach(col => {
      text += `    - ${col.column} (${col.type})${col.description ? ' // ' + col.description : ''}\n`;
    });
  }
  text += '\n';
}

const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/kowalski.md', 'utf8');
} catch (e) {
  persona = 'Kowalski, tactical and military-grade database analyst agent.';
}

return [{ json: { text, directives, kowalski_persona: persona } }];

