=### YOUR PERSONA ###
{{ $json.kowalski_persona }}

### DON JIMMY'S ANALYSIS DIRECTIVES ###
{{ $json.directives }}

### YOUR TASK ###
Based on the PostgreSQL schema structure below and Don Jimmy's directives, generate exactly 3 hypotheses to test.
For each hypothesis, write a valid read-only PostgreSQL query that aggregates or extracts stats to validate or invalidate the hypothesis.

Return a JSON object with this exact structure — no extra text, no markdown fences, just raw JSON:

{
  "queries": [
    {
      "hypothesis": "Detailed statement of your hypothesis",
      "title": "Short descriptive title for the test query",
      "sql": "SELECT ..."
    }
  ]
}

Rules:
- All SQL queries must be valid read-only PostgreSQL queries.
- Only target tables defined in the schema below.
- Output only valid JSON. No explanations, no markdown code blocks.

### SCHEMA STRUCTURE ###
{{ $json.text }}

parameters.jsCode:
const raw = $input.first().json.content || $input.first().json.response || '';
let jsonStr = raw.trim();
const firstBrace = jsonStr.indexOf('{');
const lastBrace = jsonStr.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  parsed = {
    queries: [
      {
        hypothesis: "Reddit activity represents the largest ingestion source in the database currently.",
        title: "Total post counts across sources",
        sql: "SELECT 'reddit' as src, count(*) from s_reddit.posts UNION SELECT 'substack', count(*) from s_substack.posts;"
      }
    ]
  };
}

const queries = Array.isArray(parsed.queries) ? parsed.queries : [];
return queries.map(q => ({ json: { hypothesis: q.hypothesis, title: q.title, sql: q.sql } }));

const items = $input.all();
const queryMeta = $('Parse Queries').all();

const results = items.map((item, index) => {
  const meta = queryMeta[index] ? queryMeta[index].json : { hypothesis: 'Unknown hypothesis', title: 'Unknown Query', sql: '' };
  return {
    hypothesis: meta.hypothesis,
    title: meta.title,
    sql: meta.sql,
    data: item.json.error ? null : item.json,
    error: item.json.error || null
  };
});

const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/kowalski.md', 'utf8');
} catch (e) {
  persona = 'Kowalski, tactical and military-grade database analyst agent.';
}

const directivesItem = $('Set Directives').first();
const directives = directivesItem ? directivesItem.json.directives : 'No directives provided.';

return [{ json: { results, directives, kowalski_persona: persona } }];
